  ('locality-814ced5a-moex-00255', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '社會權是人權發展到 20世紀之後增加的重要內容，其目的在充分發展個體生產和生活能力的保障及良好 地發育個體精神人格和社會人格的權利。下列何者不屬於落實社會權的行為？', '["制定《勞動事件法》協助弱勢勞工得以獲得公平的司法對待", "下修《公民投票法》的投票年齡，增進年輕公民直接民權的行使", "加重《兒童及少年性剝削防制條例》的刑責，確保兒童及少年身心健全發展", "通過《中高齡者及高齡者就業促進法》鼓勵中高齡前輩持續在職場貢獻所長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
